ps.pstext:
if !IsFeatureImplemented(FEAT_BF16) then EndOfDecode(Decode_UNDEF); end;
let n : integer = UInt(Rn);
let m : integer = UInt(M::Rm);
let d : integer = UInt(Rd);
let i : integer = UInt(H::L);
let datasize : integer{} = 64 << UInt(Q);
let elements : integer = datasize DIV 32;

AArch64_CheckFPAdvSIMDEnabled();
let operand1 : bits(datasize) = V{}(n);
let operand2 : bits(128) = V{}(m);
let operand3 : bits(datasize) = V{}(d);
var result : bits(datasize);

for e = 0 to elements-1 do
    let elt1_a : bits(16) = operand1[(2 * e + 0)*:16];
    let elt1_b : bits(16) = operand1[(2 * e + 1)*:16];
    let elt2_a : bits(16) = operand2[(2 * i + 0)*:16];
    let elt2_b : bits(16) = operand2[(2 * i + 1)*:16];

    let sum : bits(32) = operand3[e*:32];
    result[e*:32] = BFDotAdd(sum, elt1_a, elt1_b, elt2_a, elt2_b, FPCR());
end;

V{datasize}(d) = result;
